INSERT INTO public.vocabulary_translations (id, vocabulary_id, locale, meaning, example_sentence, example_pinyin, example_translation, usage_notes) VALUES
  ('d10010000-0000-0000-0000-00000000000f', 'd10010000-0000-0000-0000-000000000000', 'fr', 'aimer', '我爱我的家人。', 'Wǒ ài wǒ de jiārén.', 'J''aime ma famille.', NULL),
  ('d10010000-0000-0000-0000-00000000000e', 'd10010000-0000-0000-0000-000000000000', 'en', 'to love', '我爱我的家人。', 'Wǒ ài wǒ de jiārén.', 'I love my family.', NULL),
  ('d10020000-0000-0000-0000-00000000000f', 'd10020000-0000-0000-0000-000000000000', 'fr', 'particule de suggestion', '我们走吧。', 'Wǒmen zǒu ba.', 'Allons-y, d''accord ?', 'Ne pas confondre avec 呢 (ne) qui relance une question, pas une suggestion.'),
  ('d10020000-0000-0000-0000-00000000000e', 'd10020000-0000-0000-0000-000000000000', 'en', 'suggestion particle', '我们走吧。', 'Wǒmen zǒu ba.', 'Let''s go, shall we?', 'Don''t confuse with 呢 (ne), which follows up a question, not a suggestion.'),
  ('d10030000-0000-0000-0000-00000000000f', 'd10030000-0000-0000-0000-000000000000', 'fr', 'huit', '我有八本书。', 'Wǒ yǒu bā běn shū.', 'J''ai huit livres.', NULL),
  ('d10030000-0000-0000-0000-00000000000e', 'd10030000-0000-0000-0000-000000000000', 'en', 'eight', '我有八本书。', 'Wǒ yǒu bā běn shū.', 'I have eight books.', NULL),
  ('d10040000-0000-0000-0000-00000000000f', 'd10040000-0000-0000-0000-000000000000', 'fr', 'papa', '我爸爸是老师。', 'Wǒ bàba shì lǎoshī.', 'Mon père est professeur.', '父(père)+巴 — le caractère répété 爸爸 est une forme affectueuse enfantine.'),
  ('d10040000-0000-0000-0000-00000000000e', 'd10040000-0000-0000-0000-000000000000', 'en', 'dad', '我爸爸是老师。', 'Wǒ bàba shì lǎoshī.', 'My father is a teacher.', '父 (father) + 巴 — the doubled character 爸爸 is a childlike, affectionate form.'),
  ('d10050000-0000-0000-0000-00000000000f', 'd10050000-0000-0000-0000-000000000000', 'fr', 'cent', '这是一百块。', 'Zhè shì yìbǎi kuài.', 'Ça fait cent yuans.', NULL),
  ('d10050000-0000-0000-0000-00000000000e', 'd10050000-0000-0000-0000-000000000000', 'en', 'hundred', '这是一百块。', 'Zhè shì yìbǎi kuài.', 'That''s a hundred yuan.', NULL),
  ('d10060000-0000-0000-0000-00000000000f', 'd10060000-0000-0000-0000-000000000000', 'fr', 'la journée (de jour)', '白天我工作。', 'Báitiān wǒ gōngzuò.', 'Je travaille le jour.', 'Ne pas confondre 白天 (jour, période) et 天 seul (jour/ciel) — 白 précise "clair, de jour".'),
  ('d10060000-0000-0000-0000-00000000000e', 'd10060000-0000-0000-0000-000000000000', 'en', 'daytime', '白天我工作。', 'Báitiān wǒ gōngzuò.', 'I work during the day.', 'Don''t confuse 白天 (daytime, a period) with 天 alone (day/sky) — 白 specifies "bright, daytime".'),
  ('d10070000-0000-0000-0000-00000000000f', 'd10070000-0000-0000-0000-000000000000', 'fr', 'moitié, demi', '现在三点半。', 'Xiànzài sān diǎn bàn.', 'Il est trois heures et demie.', NULL),
  ('d10070000-0000-0000-0000-00000000000e', 'd10070000-0000-0000-0000-000000000000', 'en', 'half', '现在三点半。', 'Xiànzài sān diǎn bàn.', 'It''s half past three.', NULL),
  ('d10080000-0000-0000-0000-00000000000f', 'd10080000-0000-0000-0000-000000000000', 'fr', 'petit pain vapeur farci', '我想吃包子。', 'Wǒ xiǎng chī bāozi.', 'Je veux manger des baozi.', NULL),
  ('d10080000-0000-0000-0000-00000000000e', 'd10080000-0000-0000-0000-000000000000', 'en', 'steamed bun', '我想吃包子。', 'Wǒ xiǎng chī bāozi.', 'I want to eat baozi.', NULL),
  ('d10090000-0000-0000-0000-00000000000f', 'd10090000-0000-0000-0000-000000000000', 'fr', 'verre, tasse', '这个杯子很漂亮。', 'Zhège bēizi hěn piàoliang.', 'Ce verre est joli.', '木(bois, ancien)+不 — désigne un récipient à boire.'),
  ('d10090000-0000-0000-0000-00000000000e', 'd10090000-0000-0000-0000-000000000000', 'en', 'cup, glass', '这个杯子很漂亮。', 'Zhège bēizi hěn piàoliang.', 'This glass is pretty.', '木 (wood, archaic) + 不 — denotes a drinking vessel.'),
  ('d10100000-0000-0000-0000-00000000000f', 'd10100000-0000-0000-0000-000000000000', 'fr', 'classificateur des livres', '一本书', 'yì běn shū', 'un livre', 'Classificateur spécifique aux livres/cahiers — ne pas utiliser 个 à la place à l''écrit soigné.'),
  ('d10100000-0000-0000-0000-00000000000e', 'd10100000-0000-0000-0000-000000000000', 'en', 'classifier for books', '一本书', 'yì běn shū', 'a book', 'A classifier specific to books/notebooks — don''t use 个 instead in careful writing.'),
  ('d10110000-0000-0000-0000-00000000000f', 'd10110000-0000-0000-0000-000000000000', 'fr', 'côté, bord', '这边，那边。', 'Zhè biān, nà biān.', 'Par ici, par là.', NULL),
  ('d10110000-0000-0000-0000-00000000000e', 'd10110000-0000-0000-0000-000000000000', 'en', 'side, edge', '这边，那边。', 'Zhè biān, nà biān.', 'Over here, over there.', NULL),
  ('d10120000-0000-0000-0000-00000000000f', 'd10120000-0000-0000-0000-000000000000', 'fr', 'maladie, être malade', '他生病了。', 'Tā shēngbìng le.', 'Il est tombé malade.', '疒(radical maladie)+丙 — presque tous les caractères de maladie ont ce radical à gauche.'),
  ('d10120000-0000-0000-0000-00000000000e', 'd10120000-0000-0000-0000-000000000000', 'en', 'illness, to be sick', '他生病了。', 'Tā shēngbìng le.', 'He fell ill.', '疒 (illness radical) + 丙 — almost all illness-related characters have this radical on the left.'),
  ('d10130000-0000-0000-0000-00000000000f', 'd10130000-0000-0000-0000-000000000000', 'fr', 'ne...pas', '我不是学生。', 'Wǒ bú shì xuésheng.', 'Je ne suis pas étudiant.', '不 devient bú (2e ton) devant un 4e ton (不是, 不要) — piège de prononciation classique.'),
  ('d10130000-0000-0000-0000-00000000000e', 'd10130000-0000-0000-0000-000000000000', 'en', 'not', '我不是学生。', 'Wǒ bú shì xuésheng.', 'I am not a student.', '不 becomes bú (2nd tone) before a 4th tone (不是, 不要) — a classic pronunciation trap.'),
  ('d10140000-0000-0000-0000-00000000000f', 'd10140000-0000-0000-0000-000000000000', 'fr', 'de rien, je t''en prie', '谢谢！不客气。', 'Xièxie! Bú kèqi.', 'Merci ! De rien.', NULL),
  ('d10140000-0000-0000-0000-00000000000e', 'd10140000-0000-0000-0000-000000000000', 'en', 'you''re welcome', '谢谢！不客气。', 'Xièxie! Bú kèqi.', 'Thank you! You''re welcome.', NULL),
  ('d10150000-0000-0000-0000-00000000000f', 'd10150000-0000-0000-0000-000000000000', 'fr', 'ne pas vouloir, ne pas faire', '我不要喝咖啡。', 'Wǒ bú yào hē kāfēi.', 'Je ne veux pas boire de café.', '不要 (ne pas vouloir) vs 没要 (n''a pas demandé) — 不 nie une volonté, 没 nie un fait passé.'),
  ('d10150000-0000-0000-0000-00000000000e', 'd10150000-0000-0000-0000-000000000000', 'en', 'to not want', '我不要喝咖啡。', 'Wǒ bú yào hē kāfēi.', 'I don''t want to drink coffee.', '不要 (to not want) vs 没要 (didn''t ask for) — 不 negates a will/intention, 没 negates a past fact.'),
  ('d10160000-0000-0000-0000-00000000000f', 'd10160000-0000-0000-0000-000000000000', 'fr', 'plat, légume', '这个菜很好吃。', 'Zhège cài hěn hǎochī.', 'Ce plat est délicieux.', NULL),
  ('d10160000-0000-0000-0000-00000000000e', 'd10160000-0000-0000-0000-000000000000', 'en', 'dish, vegetable', '这个菜很好吃。', 'Zhège cài hěn hǎochī.', 'This dish is delicious.', NULL),
  ('d10170000-0000-0000-0000-00000000000f', 'd10170000-0000-0000-0000-000000000000', 'fr', 'thé', '我喜欢喝茶。', 'Wǒ xǐhuan hē chá.', 'J''aime boire du thé.', '艹(herbe)+人+木 — la plante du thé, cueillie à la main.'),
  ('d10170000-0000-0000-0000-00000000000e', 'd10170000-0000-0000-0000-000000000000', 'en', 'tea', '我喜欢喝茶。', 'Wǒ xǐhuan hē chá.', 'I like drinking tea.', '艹 (grass) + 人 + 木 — the tea plant, picked by hand.'),
  ('d10180000-0000-0000-0000-00000000000f', 'd10180000-0000-0000-0000-000000000000', 'fr', 'chanter', '她唱得很好。', 'Tā chàng de hěn hǎo.', 'Elle chante très bien.', NULL),
  ('d10180000-0000-0000-0000-00000000000e', 'd10180000-0000-0000-0000-000000000000', 'en', 'to sing', '她唱得很好。', 'Tā chàng de hěn hǎo.', 'She sings very well.', NULL),
  ('d10190000-0000-0000-0000-00000000000f', 'd10190000-0000-0000-0000-000000000000', 'fr', 'supermarché', '我去超市买东西。', 'Wǒ qù chāoshì mǎi dōngxi.', 'Je vais au supermarché faire des courses.', NULL),
  ('d10190000-0000-0000-0000-00000000000e', 'd10190000-0000-0000-0000-000000000000', 'en', 'supermarket', '我去超市买东西。', 'Wǒ qù chāoshì mǎi dōngxi.', 'I''m going to the supermarket to shop.', NULL),
  ('d10200000-0000-0000-0000-00000000000f', 'd10200000-0000-0000-0000-000000000000', 'fr', 'voiture, véhicule', '这是我的车。', 'Zhè shì wǒ de chē.', 'C''est ma voiture.', NULL),
  ('d10200000-0000-0000-0000-00000000000e', 'd10200000-0000-0000-0000-000000000000', 'en', 'car, vehicle', '这是我的车。', 'Zhè shì wǒ de chē.', 'This is my car.', NULL),
  ('d10210000-0000-0000-0000-00000000000f', 'd10210000-0000-0000-0000-000000000000', 'fr', 'manger', '我们吃饭吧。', 'Wǒmen chīfàn ba.', 'Allons manger.', '吃 (manger) vs 喝 (boire) — les débutants confondent souvent avec des liquides épais comme la soupe (on dit 喝汤, pas 吃汤).'),
  ('d10210000-0000-0000-0000-00000000000e', 'd10210000-0000-0000-0000-000000000000', 'en', 'to eat', '我们吃饭吧。', 'Wǒmen chīfàn ba.', 'Let''s go eat.', '吃 (eat) vs 喝 (drink) — beginners often mix these up with thick liquids like soup (you say 喝汤, not 吃汤).'),
  ('d10220000-0000-0000-0000-00000000000f', 'd10220000-0000-0000-0000-000000000000', 'fr', 'porter (un vêtement)', '她穿红色的衣服。', 'Tā chuān hóngsè de yīfu.', 'Elle porte des vêtements rouges.', '穿 (porter, vêtements/chaussures) vs 戴 (porter, accessoires comme lunettes/montre) — pas interchangeables.'),
  ('d10220000-0000-0000-0000-00000000000e', 'd10220000-0000-0000-0000-000000000000', 'en', 'to wear', '她穿红色的衣服。', 'Tā chuān hóngsè de yīfu.', 'She''s wearing red clothes.', '穿 (wear, clothes/shoes) vs 戴 (wear, accessories like glasses/watch) — never interchangeable.'),
  ('d10230000-0000-0000-0000-00000000000f', 'd10230000-0000-0000-0000-000000000000', 'fr', 'taxi', '我们坐出租车去吧。', 'Wǒmen zuò chūzūchē qù ba.', 'Prenons un taxi.', '出(sortir)+租(louer)+车(voiture) — littéralement "voiture à louer".'),
  ('d10230000-0000-0000-0000-00000000000e', 'd10230000-0000-0000-0000-000000000000', 'en', 'taxi', '我们坐出租车去吧。', 'Wǒmen zuò chūzūchē qù ba.', 'Let''s take a taxi.', '出 (go out) + 租 (rent) + 车 (vehicle) — literally "a car for rent".'),
  ('d10240000-0000-0000-0000-00000000000f', 'd10240000-0000-0000-0000-000000000000', 'fr', 'grand', '这个房间很大。', 'Zhège fángjiān hěn dà.', 'Cette pièce est grande.', NULL),
  ('d10240000-0000-0000-0000-00000000000e', 'd10240000-0000-0000-0000-000000000000', 'en', 'big', '这个房间很大。', 'Zhège fángjiān hěn dà.', 'This room is big.', NULL),
  ('d10250000-0000-0000-0000-00000000000f', 'd10250000-0000-0000-0000-000000000000', 'fr', 'téléphoner', '我在打电话。', 'Wǒ zài dǎ diànhuà.', 'Je suis en train de téléphoner.', '打(frapper/faire)+电话(téléphone) — littéralement "frapper un appel", 打 s''utilise pour beaucoup d''actions (打球, 打车).'),
  ('d10250000-0000-0000-0000-00000000000e', 'd10250000-0000-0000-0000-000000000000', 'en', 'to make a phone call', '我在打电话。', 'Wǒ zài dǎ diànhuà.', 'I''m on the phone.', '打 (hit/do) + 电话 (telephone) — literally "to strike a call"; 打 is used for many actions (打球, 打车).'),
  ('d10260000-0000-0000-0000-00000000000f', 'd10260000-0000-0000-0000-000000000000', 'fr', 'tout le monde', '大家好！', 'Dàjiā hǎo!', 'Bonjour à tous !', NULL),
  ('d10260000-0000-0000-0000-00000000000e', 'd10260000-0000-0000-0000-000000000000', 'en', 'everyone', '大家好！', 'Dàjiā hǎo!', 'Hello, everyone!', NULL),
