  ('d10280000-0000-0000-0000-00000000000e', 'd10280000-0000-0000-0000-000000000000', 'en', 'university', '她在大学学习。', 'Tā zài dàxué xuéxí.', 'She studies at university.', NULL),
  ('d10290000-0000-0000-0000-00000000000f', 'd10290000-0000-0000-0000-000000000000', 'fr', 'étudiant universitaire', '我是大学生。', 'Wǒ shì dàxuéshēng.', 'Je suis étudiant universitaire.', NULL),
  ('d10290000-0000-0000-0000-00000000000e', 'd10290000-0000-0000-0000-000000000000', 'en', 'university student', '我是大学生。', 'Wǒ shì dàxuéshēng.', 'I am a university student.', NULL),
  ('d10300000-0000-0000-0000-00000000000f', 'd10300000-0000-0000-0000-000000000000', 'fr', 'particule possessive', '这是我的书。', 'Zhè shì wǒ de shū.', 'C''est mon livre.', '的 (possessif, devant nom) vs 得 (complément, après verbe) vs 地 (adverbial, avant verbe) — même son "de", trois fonctions distinctes.'),
  ('d10300000-0000-0000-0000-00000000000e', 'd10300000-0000-0000-0000-000000000000', 'en', 'possessive particle', '这是我的书。', 'Zhè shì wǒ de shū.', 'This is my book.', '的 (possessive, before a noun) vs 得 (complement, after a verb) vs 地 (adverbial, before a verb) — same sound "de", three distinct functions.'),
