  ('d10320000-0000-0000-0000-00000000000e', 'd10320000-0000-0000-0000-000000000000', 'en', 'shop, store', '这家店很有名。', 'Zhè jiā diàn hěn yǒumíng.', 'This shop is famous.', NULL),
