  ('d10330000-0000-0000-0000-00000000000e', 'd10330000-0000-0000-0000-000000000000', 'en', 'o''clock; a bit; point', '现在几点？', 'Xiànzài jǐ diǎn?', 'What time is it?', NULL),
  ('d10340000-0000-0000-0000-00000000000f', 'd10340000-0000-0000-0000-000000000000', 'fr', 'téléphone', '你的电话号码是什么？', 'Nǐ de diànhuà hàomǎ shì shénme?', 'Quel est ton numéro de téléphone ?', NULL),
  ('d10340000-0000-0000-0000-00000000000e', 'd10340000-0000-0000-0000-000000000000', 'en', 'telephone', '你的电话号码是什么？', 'Nǐ de diànhuà hàomǎ shì shénme?', 'What''s your phone number?', NULL),
  ('d10350000-0000-0000-0000-00000000000f', 'd10350000-0000-0000-0000-000000000000', 'fr', 'ordinateur', '我的电脑坏了。', 'Wǒ de diànnǎo huài le.', 'Mon ordinateur est cassé.', '电(électricité)+脑(cerveau) — littéralement "cerveau électrique".'),
  ('d10350000-0000-0000-0000-00000000000e', 'd10350000-0000-0000-0000-000000000000', 'en', 'computer', '我的电脑坏了。', 'Wǒ de diànnǎo huài le.', 'My computer is broken.', '电 (electricity) + 脑 (brain) — literally "electric brain".'),
