  ('d10360000-0000-0000-0000-00000000000e', 'd10360000-0000-0000-0000-000000000000', 'en', 'television', '我们看电视吧。', 'Wǒmen kàn diànshì ba.', 'Let''s watch TV.', NULL),
  ('d10370000-0000-0000-0000-00000000000f', 'd10370000-0000-0000-0000-000000000000', 'fr', 'film', '这个电影很好看。', 'Zhège diànyǐng hěn hǎokàn.', 'Ce film est très bien.', NULL),
  ('d10370000-0000-0000-0000-00000000000e', 'd10370000-0000-0000-0000-000000000000', 'en', 'film', '这个电影很好看。', 'Zhège diànyǐng hěn hǎokàn.', 'This film is very good.', NULL),
  ('d10380000-0000-0000-0000-00000000000f', 'd10380000-0000-0000-0000-000000000000', 'fr', 'cinéma', '我们去电影院吧。', 'Wǒmen qù diànyǐngyuàn ba.', 'Allons au cinéma.', NULL),
  ('d10380000-0000-0000-0000-00000000000e', 'd10380000-0000-0000-0000-000000000000', 'en', 'cinema', '我们去电影院吧。', 'Wǒmen qù diànyǐngyuàn ba.', 'Let''s go to the cinema.', NULL),
  ('d10390000-0000-0000-0000-00000000000f', 'd10390000-0000-0000-0000-000000000000', 'fr', 'petit frère', '我弟弟很高。', 'Wǒ dìdi hěn gāo.', 'Mon petit frère est grand.', NULL),
  ('d10390000-0000-0000-0000-00000000000e', 'd10390000-0000-0000-0000-000000000000', 'en', 'younger brother', '我弟弟很高。', 'Wǒ dìdi hěn gāo.', 'My younger brother is tall.', NULL),
  ('d10400000-0000-0000-0000-00000000000f', 'd10400000-0000-0000-0000-000000000000', 'fr', 'chose, objet', '我要买东西。', 'Wǒ yào mǎi dōngxi.', 'Je veux acheter des choses.', '东(est)+西(ouest) — à l''origine "d''est en ouest", puis "choses en général".'),
  ('d10400000-0000-0000-0000-00000000000e', 'd10400000-0000-0000-0000-000000000000', 'en', 'thing, object', '我要买东西。', 'Wǒ yào mǎi dōngxi.', 'I want to buy some things.', '东 (east) + 西 (west) — originally "from east to west", later "things in general".'),
