  ('d10410000-0000-0000-0000-00000000000e', 'd10410000-0000-0000-0000-000000000000', 'en', 'all', '我们都是学生。', 'Wǒmen dōu shì xuésheng.', 'We are all students.', NULL),
  ('d10420000-0000-0000-0000-00000000000f', 'd10420000-0000-0000-0000-000000000000', 'fr', 'lire', '我喜欢读书。', 'Wǒ xǐhuan dú shū.', 'J''aime lire.', NULL),
  ('d10420000-0000-0000-0000-00000000000e', 'd10420000-0000-0000-0000-000000000000', 'en', 'to read', '我喜欢读书。', 'Wǒ xǐhuan dú shū.', 'I like reading.', NULL),
  ('d10430000-0000-0000-0000-00000000000f', 'd10430000-0000-0000-0000-000000000000', 'fr', 'correct, envers', '你说得对。', 'Nǐ shuō de duì.', 'Tu as raison.', NULL),
  ('d10430000-0000-0000-0000-00000000000e', 'd10430000-0000-0000-0000-000000000000', 'en', 'correct; towards', '你说得对。', 'Nǐ shuō de duì.', 'You''re right.', NULL),
  ('d10440000-0000-0000-0000-00000000000f', 'd10440000-0000-0000-0000-000000000000', 'fr', 'pardon, désolé', '对不起，我错了。', 'Duìbuqǐ, wǒ cuò le.', 'Désolé, j''ai eu tort.', NULL),
