  ('d10450000-0000-0000-0000-00000000000e', 'd10450000-0000-0000-0000-000000000000', 'en', 'many, much', '这儿人很多。', 'Zhèr rén hěn duō.', 'There are many people here.', NULL),
  ('d10460000-0000-0000-0000-00000000000f', 'd10460000-0000-0000-0000-000000000000', 'fr', 'combien', '这个多少钱？', 'Zhège duōshao qián?', 'Combien ça coûte ?', '多少 (combien, sans limite) vs 几 (combien, petit nombre <10) — 多少 pour un prix, 几 pour "combien d''heures".'),
  ('d10460000-0000-0000-0000-00000000000e', 'd10460000-0000-0000-0000-000000000000', 'en', 'how much', '这个多少钱？', 'Zhège duōshao qián?', 'How much does it cost?', '多少 (how much, no upper limit) vs 几 (how many, small number <10) — 多少 for a price, 几 for "how many hours".'),
  ('d10470000-0000-0000-0000-00000000000f', 'd10470000-0000-0000-0000-000000000000', 'fr', 'étudier, lire (des livres)', '他在家读书。', 'Tā zài jiā dúshū.', 'Il étudie à la maison.', NULL),
  ('d10470000-0000-0000-0000-00000000000e', 'd10470000-0000-0000-0000-000000000000', 'en', 'to study, to read', '他在家读书。', 'Tā zài jiā dúshū.', 'He studies at home.', NULL),
  ('d10480000-0000-0000-0000-00000000000f', 'd10480000-0000-0000-0000-000000000000', 'fr', 'deux', '我有二十岁。', 'Wǒ yǒu èrshí suì.', 'J''ai vingt ans.', '二 (chiffre "deux" en comptant/nombres) vs 两 (deux devant un classificateur : 两个) — 二十 mais 两个人.'),
  ('d10480000-0000-0000-0000-00000000000e', 'd10480000-0000-0000-0000-000000000000', 'en', 'two', '我有二十岁。', 'Wǒ yǒu èrshí suì.', 'I am twenty years old.', '二 (the digit "two" when counting/numbers) vs 两 (two before a classifier: 两个) — 二十 but 两个人.'),
  ('d10490000-0000-0000-0000-00000000000f', 'd10490000-0000-0000-0000-000000000000', 'fr', 'fils', '他的儿子很可爱。', 'Tā de érzi hěn kě''ài.', 'Son fils est mignon.', NULL),
